class Solution:
    def answerString(self, word, numFriends):
        n = len(word)
        best = ""
        for i in range(n):
            left_needs = 1 if i > 0 else 0
            for L in range(1, n - i + 1):
                right_len = n - i - L
                right_needs = 1 if right_len > 0 else 0
                remaining = n - L
                lo = left_needs + right_needs
                if lo <= numFriends - 1 <= remaining:
                    cand = word[i:i + L]
                    if cand > best:
                        best = cand
        return best

