class Solution:
    def answerString(self, word, numFriends):
        n = len(word)
        if numFriends == 1:
            return word
        maxLen = n - numFriends + 1
        best = ""
        for i in range(numFriends - 1):
            cand = word[i:i + maxLen]
            if cand > best:
                best = cand
        for i in range(numFriends - 1, n):
            cand = word[i:n]
            if cand > best:
                best = cand
        return best

