var answerString = function(word, numFriends) {
    const n = word.length;
    if (numFriends === 1) return word;
    const maxLen = n - numFriends + 1;
    let best = "";
    for (let i = 0; i < numFriends - 1; i++) {
        const cand = word.slice(i, i + maxLen);
        if (cand > best) best = cand;
    }
    for (let i = numFriends - 1; i < n; i++) {
        const cand = word.slice(i, n);
        if (cand > best) best = cand;
    }
    return best;
};
